        // 使用单例的管理器进行本地化
        LocalizedStringManager.Instance.AddLocalizedText(
            m_nameText,
            "CardLocalization",
            cardObject.GetDataBaseID() + "_Name",
            () => cardObject.GetName());

        LocalizedStringManager.Instance.AddLocalizedText(
            m_descriptionText,
            "CardLocalization",
            cardObject.GetDataBaseID() + "_Description",
            () => cardObject.GetDescription());
